import React from 'react';
import { Grid, Paper, Button, Typography, TextField } from '@mui/material';
import { makeStyles } from '@mui/styles';
import { useNavigate } from 'react-router-dom';
import signpng from './signupfinal.png';
import signback from './signback.png'

const useStyles = makeStyles((theme) => ({
  image: {
    width: 'auto',
    height: '600px',
    boxShadow: '10px 0px 5px red',
  },
  image2: {
    width: 'auto',
    height: '600px',
    margin:'0 0 '
  },
}));

export const Signup = () => {
  const navigate = useNavigate();
  const classes = useStyles();

  return (
    <Grid
      container
      justifyContent="center"
      alignItems="center"
      style={{ minHeight: '100vh' }}
    >
    <Paper sx={{ padding:'20px,200px,0px,0px',  width: '1200px', height: '600px' }} elevation={10}>

        <Grid container>
        
        <Grid item xs={0} >
            <img src={signpng} alt="The signup" className={classes.image} />
            <img src={signback} alt="The signup" className={classes.image} />
        </Grid>

        
        <Grid item xs={7} container justifyContent="center" alignItems="center">

            <Typography variant="h2">Hello world how are you</Typography>
            
            <TextField label="Name" variant="outlined" fullWidth margin="normal" />
            <TextField label="Password" type="password" variant="outlined" fullWidth margin="normal" />
            <Button variant="contained" onClick={() => { navigate('/signup') }}>Signup</Button>

        </Grid>
        </Grid>
    </Paper>
    </Grid>
);
};
